<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #121212;
            --surface-color: #1e1e1e;
            --primary-color: #bb86fc;
            --secondary-color: #03dac6;
            --error-color: #cf6679;
            --text-primary: #ffffff;
            --text-secondary: #b0b0b0;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            font-family: 'Roboto', sans-serif;
        }

        body {
            background-color: var(--bg-color);
            color: var(--text-primary);
            display: flex;
            flex-direction: column;
            align-items: center;
            min-height: 100vh;
            padding: 20px;
        }

        h1 {
            margin-bottom: 20px;
            font-weight: 300;
            letter-spacing: 1px;
        }

        .controls-container {
            display: flex;
            gap: 15px;
            margin-bottom: 20px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            background-color: var(--surface-color);
            color: var(--text-primary);
            border: none;
            padding: 10px 20px;
            font-size: 14px;
            border-radius: 4px;
            cursor: pointer;
            transition: all 0.2s ease;
            box-shadow: 0 2px 5px rgba(0,0,0,0.3);
            min-width: 80px;
        }

        button:hover {
            transform: translateY(-1px);
            box-shadow: 0 4px 8px rgba(0,0,0,0.4);
        }

        button:active {
            transform: translateY(1px);
            box-shadow: 0 2px 3px rgba(0,0,0,0.3);
        }

        #mat-sand { border-left: 5px solid #e6b800; }
        #mat-water { border-left: 5px solid #4da6ff; }
        #mat-wall { border-left: 5px solid #757575; }
        #mat-acid { border-left: 5px solid #76ff03; }
        #mat-empty { border-left: 5px solid #cf6679; }

        button.active {
            background-color: var(--primary-color);
            color: #000;
            font-weight: bold;
        }

        .canvas-container {
            position: relative;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            border-radius: 8px;
            overflow: hidden;
        }

        canvas {
            display: block;
            background-color: #000;
            cursor: crosshair;
        }

        .info {
            margin-top: 15px;
            color: var(--text-secondary);
            font-size: 14px;
            text-align: center;
        }
    </style>
</head>
<body>
    <h1>Falling Sand Sandbox</h1>

    <div class="controls-container">
        <button id="mat-sand" class="active">Sand</button>
        <button id="mat-water">Water</button>
        <button id="mat-wall">Wall</button>
        <button id="mat-acid">Acid</button>
        <button id="mat-empty">Eraser</button>
    </div>

    <div class="controls-container">
        <button id="clear">Clear All</button>
    </div>

    <div class="canvas-container">
        <canvas id="sand" width="400" height="400"></canvas>
    </div>

    <div class="info">
        Left-click to paint. Select material above.
    </div>

    <script>
        // Configuration
        const GRID_WIDTH = 80;
        const GRID_HEIGHT = 80;
        const CELL_SIZE = 5; // 400 / 80 = 5

        // Material constants
        const EMPTY = 0;
        const SAND = 1;
        const WATER = 2;
        const WALL = 3;
        const ACID = 4;

        // Color mapping for materials
        const COLORS = {
            [EMPTY]: '#000000',
            [SAND]: '#e6b800',
            [WATER]: '#4da6ff',
            [WALL]: '#757575',
            [ACID]: '#76ff03'
        };

        // Grid state
        let grid = [];

        // Current selected material for painting
        let currentMaterial = SAND;

        // Mouse interaction state
        let isMouseDown = false;
        let mouseX = 0;
        let mouseY = 0;

        // Initialize the simulation
        function init() {
            // Create empty grid
            grid = new Array(GRID_HEIGHT).fill(0).map(() => new Array(GRID_WIDTH).fill(EMPTY));

            // Setup canvas
            const canvas = document.getElementById('sand');
            canvas.width = GRID_WIDTH * CELL_SIZE;
            canvas.height = GRID_HEIGHT * CELL_SIZE;

            // Setup event listeners for painting
            setupCanvasEvents(canvas);

            // Setup button events
            setupButtonEvents();

            // Start animation loop
            requestAnimationFrame(animate);
        }

        function setupCanvasEvents(canvas) {
            const rect = canvas.getBoundingClientRect();

            canvas.addEventListener('mousedown', (e) => {
                isMouseDown = true;
                updateMousePos(e, rect);
                paintAtMouse();
            });

            canvas.addEventListener('mousemove', (e) => {
                if (isMouseDown) {
                    updateMousePos(e, rect);
                    paintAtMouse();
                }
            });

            window.addEventListener('mouseup', () => {
                isMouseDown = false;
            });
        }

        function setupButtonEvents() {
            const buttons = [
                { id: 'mat-sand', material: SAND },
                { id: 'mat-water', material: WATER },
                { id: 'mat-wall', material: WALL },
                { id: 'mat-acid', material: ACID },
                { id: 'mat-empty', material: EMPTY }
            ];

            buttons.forEach(btn => {
                const element = document.getElementById(btn.id);
                element.addEventListener('click', () => {
                    // Remove active class from all buttons
                    document.querySelectorAll('.controls-container button').forEach(b => b.classList.remove('active'));
                    // Add active class to clicked button
                    element.classList.add('active');
                    currentMaterial = btn.material;
                });
            });

            const clearBtn = document.getElementById('clear');
            clearBtn.addEventListener('click', () => {
                grid.forEach(row => row.fill(EMPTY));
            });
        }

        function updateMousePos(e, rect) {
            mouseX = Math.floor((e.clientX - rect.left) / CELL_SIZE);
            mouseY = Math.floor((e.clientY - rect.top) / CELL_SIZE);
        }

        function paintAtMouse() {
            // Paint a small brush (3x3 area)
            const brushSize = 2;

            for (let y = -brushSize; y <= brushSize; y++) {
                for (let x = -brushSize; x <= brushSize; x++) {
                    const px = mouseX + x;
                    const py = mouseY + y;

                    // Check bounds
                    if (px >= 0 && px < GRID_WIDTH && py >= 0 && py < GRID_HEIGHT) {
                        // Don't overwrite with same material to avoid unnecessary updates
                        if (grid[py][px] !== currentMaterial) {
                            grid[py][px] = currentMaterial;
                        }
                    }
                }
            }
        }

        function get(x, y) {
            if (x < 0 || x >= GRID_WIDTH || y < 0 || y >= GRID_HEIGHT) return EMPTY;
            return grid[y][x];
        }

        function set(x, y, material) {
            if (x >= 0 && x < GRID_WIDTH && y >= 0 && y < GRID_HEIGHT) {
                grid[y][x] = material;
            }
        }

        function clear() {
            grid.forEach(row => row.fill(EMPTY));
        }

        // Core simulation logic
        function tick(n = 1) {
            for (let step = 0; step < n; step++) {
                // Process from bottom to top to ensure particles move at most one cell per step
                for (let y = GRID_HEIGHT - 1; y >= 0; y--) {
                    // Randomize x-direction traversal each frame for more natural behavior
                    const leftToRight = Math.random() > 0.5;

                    for (let i = 0; i < GRID_WIDTH; i++) {
                        const x = leftToRight ? i : GRID_WIDTH - 1 - i;

                        // Skip empty cells
                        if (grid[y][x] === EMPTY) continue;

                        switch (grid[y][x]) {
                            case SAND:
                                updateSand(x, y);
                                break;
                            case WATER:
                                updateWater(x, y);
                                break;
                            case ACID:
                                updateAcid(x, y);
                                break;
                            // WALL and other materials don't move
                        }
                    }
                }
            }
        }

        function updateSand(x, y) {
            // Try to fall down
            if (y < GRID_HEIGHT - 1) {
                const below = grid[y + 1][x];

                // Fall into empty space or swap with water/acid
                if (below === EMPTY || below === WATER || below === ACID) {
                    if (below === WATER || below === ACID) {
                        // Swap positions
                        grid[y][x] = below;
                        grid[y + 1][x] = SAND;
                    } else {
                        // Fall into empty
                        grid[y][x] = EMPTY;
                        grid[y + 1][x] = SAND;
                    }
                } 
                // Try diagonal movement if blocked directly below
                else {
                    const dir = Math.random() > 0.5 ? 1 : -1;

                    // Check both diagonals
                    for (let d of [dir, -dir]) {
                        if (x + d >= 0 && x + d < GRID_WIDTH) {
                            const belowSide = grid[y + 1][x + d];
                            if (belowSide === EMPTY || belowSide === WATER || belowSide === ACID) {
                                if (belowSide === WATER || belowSide === ACID) {
                                    // Swap positions
                                    grid[y][x] = belowSide;
                                    grid[y + 1][x + d] = SAND;
                                } else {
                                    // Fall into empty
                                    grid[y][x] = EMPTY;
                                    grid[y + 1][x + d] = SAND;
                                }
                                break; // Movement successful, stop checking other diagonals
                            }
                        }
                    }
                }
            }
        }

        function updateWater(x, y) {
            if (y < GRID_HEIGHT - 1) {
                const below = grid[y + 1][x];

                // Try to fall down
                if (below === EMPTY) {
                    grid[y][x] = EMPTY;
                    grid[y + 1][x] = WATER;
                } else if (below === SAND || below === WALL || below === ACID) {
                    // Can't fall through these, try diagonal movement
                    const dir = Math.random() > 0.5 ? 1 : -1;

                    for (let d of [dir, -dir]) {
                        if (x + d >= 0 && x + d < GRID_WIDTH) {
                            const belowSide = grid[y + 1][x + d];
                            if (belowSide === EMPTY) {
                                grid[y][x] = EMPTY;
                                grid[y + 1][x + d] = WATER;
                                break;
                            }
                        }
                    }
                } else if (below === WATER || below === ACID) {
                    // Swap with other liquid
                    grid[y][x] = below;
                    grid[y + 1][x] = WATER;
                }
            }

            // Horizontal spreading when blocked below or after falling
            if (y < GRID_HEIGHT - 1 && 
                (grid[y + 1][x] !== EMPTY && grid[y + 1][x] !== WATER && grid[y + 1][x] !== ACID)) {

                const dir = Math.random() > 0.5 ? 1 : -1;

                for (let d of [dir, -dir]) {
                    if (x + d >= 0 && x + d < GRID_WIDTH) {
                        if (grid[y][x + d] === EMPTY) {
                            grid[y][x] = EMPTY;
                            grid[y][x + d] = WATER;
                            break; // Spread successful
                        }
                    }
                }
            } else if (y === GRID_HEIGHT - 1 || (y < GRID_HEIGHT - 1 && grid[y + 1][x] === EMPTY)) {
                // If we just fell, try to spread horizontally too
                const dir = Math.random() > 0.5 ? 1 : -1;

                for (let d of [dir, -dir]) {
                    if (x + d >= 0 && x + d < GRID_WIDTH) {
                        if (grid[y][x + d] === EMPTY) {
                            grid[y][x] = EMPTY;
                            grid[y][x + d] = WATER;
                            break;
                        }
                    }
                }
            }
        }

        function updateAcid(x, y) {
            // Acid moves like water but also dissolves nearby materials
            if (y < GRID_HEIGHT - 1) {
                const below = grid[y + 1][x];

                // Try to fall down
                if (below === EMPTY || below === SAND || below === WALL) {
                    grid[y][x] = EMPTY;
                    grid[y + 1][x] = ACID;

                    // Dissolve the material we fell through
                    if (below === SAND || below === WALL) {
                        grid[y + 1][x] = Math.random() > 0.5 ? EMPTY : ACID; // Acid might disappear too
                    }
                } else if (below === WATER) {
                    // Swap with water and potentially neutralize
                    grid[y][x] = below;
                    grid[y + 1][x] = ACID;

                    // Neutralization chance
                    if (Math.random() > 0.8) {
                        grid[y + 1][x] = EMPTY; // Acid disappears
                        grid[y][x] = WATER;     // Water remains
                    }
                } else if (below === ACID) {
                    // Swap with acid
                    grid[y][x] = below;
                    grid[y + 1][x] = ACID;
                }
            }

            // Horizontal spreading and dissolution
            const dir = Math.random() > 0.5 ? 1 : -1;

            for (let d of [dir, -dir]) {
                if (x + d >= 0 && x + d < GRID_WIDTH) {
                    const side = grid[y][x + d];

                    // Spread into empty
                    if (side === EMPTY) {
                        grid[y][x] = EMPTY;
                        grid[y][x + d] = ACID;
                        break; // Spread successful
                    }
                    // Dissolve sand or wall
                    else if (side === SAND || side === WALL) {
                        grid[y][x] = Math.random() > 0.5 ? EMPTY : ACID; // Acid might disappear
                        grid[y][x + d] = EMPTY; // Target dissolves
                        break;
                    }
                }
            }
        }

        function draw() {
            const canvas = document.getElementById('sand');
            const ctx = canvas.getContext('2d');

            // Clear canvas
            ctx.fillStyle = COLORS[EMPTY];
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Draw grid cells
            for (let y = 0; y < GRID_HEIGHT; y++) {
                for (let x = 0; x < GRID_WIDTH; x++) {
                    const material = grid[y][x];

                    if (material !== EMPTY) {
                        ctx.fillStyle = COLORS[material];

                        // Add slight variation to colors for texture
                        if (material === SAND && Math.random() > 0.95) {
                            ctx.fillStyle = '#d4a600';
                        } else if (material === WATER && Math.random() > 0.95) {
                            ctx.fillStyle = '#3d94e6';
                        }

                        // Draw cell
                        ctx.fillRect(
                            x * CELL_SIZE, 
                            y * CELL_SIZE, 
                            CELL_SIZE, 
                            CELL_SIZE
                        );
                    }
                }
            }
        }

        function animate() {
            tick(1);
            draw();
            requestAnimationFrame(animate);
        }

        // Expose API to window as required
        window.sim = {
            w: GRID_WIDTH,
            h: GRID_HEIGHT,

            tick(n) {
                tick(n || 1);
            },

            get(x, y) {
                const mat = get(x, y);
                return ['empty', 'sand', 'water', 'wall', 'acid'][mat];
            },

            set(x, y, material) {
                const matMap = {
                    'empty': EMPTY,
                    'sand': SAND,
                    'water': WATER,
                    'wall': WALL,
                    'acid': ACID
                };

                if (matMap[material] !== undefined) {
                    set(x, y, matMap[material]);
                }
            },

            clear() {
                clear();
            }
        };

        // Initialize the simulation when page loads
        window.addEventListener('load', init);
    </script>
</body>
</html>
